export const OVERALL_CATEGORIES: string[] = Object.keys(CATALOG_BY_CATEGORY).sort();

export function itemsForOverall(cat: string): CatalogItem[] {
  return CATALOG_BY_CATEGORY[cat] ?? [];
}
export function itemByName(cat: string, name: string): CatalogItem | undefined {
  return itemsForOverall(cat).find((i) => i.name === name);
}